var expect = require('expect.js');
var RuleView = require('../../res/page/ruleview/ruleview');

describe('sqlscan-ruleview', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init RuleView()', function(){
    it('init RuleView', function(done){
      var ruleview = RuleView._create({
        events : {
          'afterruleviewlistload' : function(){
            expect(ruleview).to.be.ok();
            var owner = this.query('combobox[name="owner"]');
            expect(owner).to.be.ok();
            var appId = this.query('combobox[name="appid"]');
            expect(appId).to.be.ok();
            var ruleName = this.query('combobox[name="rulename"]');
            expect(ruleName).to.be.ok();
            var rulelist = this.query('list[name="rulelist"]');
            expect(rulelist).to.be.ok();
            expect(rulelist.data.records.length).to.be(6);
            done();
          }
        }
      });
    });
  });
  describe('#searchRules events', function(){
    it('searchRules', function(done){
      var ruleview = RuleView._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            var owner = this.query('combobox[name="owner"]');
            expect(owner).to.be.ok();
            var appId = this.query('combobox[name="appid"]');
            expect(appId).to.be.ok();
            var ruleName = this.query('combobox[name="rulename"]');
            expect(ruleName).to.be.ok();
            this.on('afterruleviewlistload', function(){
              var rulelist = _self.query('list[name="rulelist"]');
              expect(rulelist).to.be.ok();
              expect(rulelist.data.records.length).to.be(6);
            });
            var btnSearch = _self.query('button[name="btnSearch"]');
            btnSearch.emit('click');
            done();
          }
        }
      });
    });
  });
  describe('#rowClickEvent events', function(){
    it('rowClickEvent', function(done){
      var ruleview = RuleView._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            var rulelist = _self.query('list[name="rulelist"]');
            expect(rulelist).to.be.ok();
            var row = $('.rule-list', rulelist.el).eq(0);
            row.trigger({
              type : 'click',
              target : $('.rule-desc', row)
            });
            expect(this.checkRowClick).to.be.ok();
            row.trigger({
              type : 'click',
              target : $('.rule-desc', row)
            });
            expect(this.checkRowClick).not.to.be.ok();
            row.trigger({
              type : 'click',
              target : $('label', row)
            });
          },
          'showauthorizerange' : function(){
            expect(this.win).to.be.ok();
            done();
          }
        }
      });
    });
  });
  describe('#tabclick events', function(){
    it('tabclick', function(done){
      var ruleview = RuleView._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            this.on('afterruleviewlistload', function(){
              var rulelist = _self.query('list[name="rulelist"]');
              expect(rulelist).to.be.ok();
              expect(rulelist.data.records.length).to.be(6);
            });
            var ftab = $('.rulelist-tab', this.el).children("span:first");
            var stab = $('.rulelist-tab', this.el).children("span:last");
            ftab.trigger('click');
            expect(ftab[0].className).to.be('rulelist-tab-active');
            expect(stab[0].className).to.be('rulelist-tab-deactive');
            stab.trigger('click');
            expect(ftab[0].className).to.be('rulelist-tab-deactive');
            expect(stab[0].className).to.be('rulelist-tab-active');
            done();
          }
        }
      });
    });
  });
});